	buf := bufPool.Get().(*bytes.Buffer)
	defer func() {
		buf.Reset()      // clear before returning so the next user starts clean
		bufPool.Put(buf)
	}()

	buf.WriteByte('[')
	buf.WriteString(msg)
	buf.WriteByte(']')
	return buf.String()
}

func main() {
	fmt.Println(render("hello"))
	fmt.Println(render("world"))
}
